# ---- EXERCISE DATA (30 entries, cycling full/upper/lower/rest) ----
def _make_ex(type_, title, subtitle, duration, level, warmup, circuits, cooldown="", rest_activities=None):
    return {"type": type_, "title": title, "subtitle": subtitle, "duration": duration,
            "level": level, "warmup": warmup or [], "circuits": circuits or [],
            "cooldown": cooldown, "restActivities": rest_activities or []}

def _ex(icon, icon_class, name, desc, reps):
    return {"icon": icon, "iconClass": icon_class, "name": name, "desc": desc, "reps": reps}

def _circuit(label, title, exercises):
    return {"label": label, "title": title, "exercises": exercises}

_rest = lambda title, sub, acts: _make_ex("rest", title, sub, "Light only", "Active rest", [], [], "", acts)

